    _orig_grad = None

_orig_requires_grad = getattr(tensor_cls, "requires_grad", None)
if not callable(_orig_requires_grad):
    _orig_requires_grad = None

_orig_set_requires_grad = getattr(tensor_cls, "set_requires_grad", None)
