ctx_state = dict(getattr(ctx, "__dict__", {}))

create_node(
    cls,
    tuple(tensor_inputs),
    primary_tensor,
    tuple(saved),
    tuple(needs_input_grad),
    tuple(edge_index_by_arg),
    ctx_state,
